import { z } from "zod";
import { defineApi } from "../../../howl.config.ts";

export default defineApi({
  name: "Ping",
  directory: "public",        // OpenAPI tag
  method: "GET",
  roles: [],                   // empty = public, no auth
  rateLimit: { max: 30, windowMs: 60_000 },
  caching: { ttl: 5 },         // cache 2xx responses for 5s
  responses: {
    200: z.object({ ok: z.boolean(), message: z.string() }),
  },
  handler: () => ({
    statusCode: 200,
    ok: true,
    message: `pong — ${new Date().toISOString()}`,
  }),
});

export default defineApi({
  name: "Create User",
  directory: "users",
  method: "POST",
  roles: [],
  requestBody: z.object({
    email: z.email(),
    name: z.string().min(1),
    role: z.enum(["reader", "author"]).optional(),
  }),
  responses: { 200: z.object({ data: z.any() }) },
  handler: async (ctx) => {
    // ctx.req.body is fully typed from requestBody
    const data = await usersService.create(ctx.req.body, { executionerId: "api" });
    return { status: 200, data };
  },
});

// handler returns:
return { status: 200, data: [1, 2, 3] };
// client receives:
// 200  { "ok": true, "data": [1, 2, 3] }

// handler returns:
return { statusCode: 201, id: "abc" };
// client receives:
// 201  { "ok": true, "id": "abc" }

import { HttpError } from "@hushkey/howl";

handler: async (ctx) => {
  const user = await users.get(ctx.params.id);
  if (!user) throw new HttpError(404, "User not found");
  return { status: 200, data: user };
}

before: [
  async (ctx, app) => { await audit.log({ path: ctx.url.pathname }); },
],
after: [
  async (ctx, response, app) => { await metrics.record(response.status); },
],
